import React, { useEffect, useState } from 'react';
import Swal from 'sweetalert2';
import { Link } from 'react-router-dom'; // If you're using React Router

const ManageOfficers = () => {
    const [officers, setOfficers] = useState([]);

    useEffect(() => {
        const fetchOfficers = async () => {
            try {
                const response = await fetch('/api/officers'); // Replace with your API endpoint
                const data = await response.json();
                setOfficers(data);
            } catch (error) {
                console.error('Error fetching officers:', error);
            }
        };

        fetchOfficers();
    }, []);

    const confirmDelete = (officerId) => {
        Swal.fire({
            title: 'Are you sure?',
            text: "You won't be able to revert this!",
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#3085d6',
            cancelButtonColor: '#d33',
            confirmButtonText: 'Yes, delete it!'
        }).then(async (result) => {
            if (result.isConfirmed) {
                try {
                    await fetch(`/api/officers/${officerId}`, { method: 'DELETE' });
                    setOfficers(officers.filter(officer => officer.id !== officerId));
                    Swal.fire('Deleted!', 'The officer has been deleted.', 'success');
                } catch (error) {
                    console.error('Error deleting officer:', error);
                    Swal.fire('Error!', 'There was an error deleting the officer.', 'error');
                }
            }
        });
    };

    return (
        <div className="container">
            <h2>Manage Officers</h2>
            <table className="table">
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Name</th>
                        <th>Role</th>
                        <th>Email</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    {officers.length > 0 ? (
                        officers.map(officer => (
                            <tr key={officer.id}>
                                <td>{officer.id}</td>
                                <td>{officer.name}</td>
                                <td>{officer.role}</td>
                                <td>{officer.email}</td>
                                <td>
                                    <Link to={`/update-officer/${officer.id}`} className="btn btn-primary">Update</Link>
                                    <button
                                        onClick={() => confirmDelete(officer.id)}
                                        className="btn btn-danger"
                                        style={{ marginLeft: '10px' }}
                                    >
                                        Delete
                                    </button>
                                </td>
                            </tr>
                        ))
                    ) : (
                        <tr>
                            <td colSpan="5">No records found</td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>
    );
};

export default ManageOfficers;
